import numpy as np

def select_next_node(current_node, truck_nodes, depot_node, unvisited_nodes, distance_matrix):
    next_node = None
    min_distance = np.inf

    for node in unvisited_nodes:
        if current_node != node:
            min_dist_truck_nodes = np.mean([distance_matrix[node, truck_node] for truck_node in truck_nodes])
            dist_depot = distance_matrix[current_node, depot_node]
            dist = distance_matrix[current_node, node] / (1 + min_dist_truck_nodes) / (1 + dist_depot)
            if dist < min_distance:
                min_distance = dist
                next_node = node

    return next_node
